package main

import (
	"fmt"
	"log"
	"net/http"

	"authserver/auth"
)

func main() {
	mux := http.NewServeMux()

	mux.HandleFunc("/login", func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
			return
		}

		username := r.FormValue("username")
		password := r.FormValue("password")

		token, err := auth.Login(username, password)
		if err != nil {
			http.Error(w, err.Error(), http.StatusUnauthorized)
			return
		}

		fmt.Fprintf(w, `{"token":"%s"}`, token)
	})

	mux.HandleFunc("/protected", func(w http.ResponseWriter, r *http.Request) {
		token := r.Header.Get("Authorization")

		user, err := auth.ValidateToken(token)
		if err != nil {
			http.Error(w, "unauthorized", http.StatusUnauthorized)
			return
		}

		fmt.Fprintf(w, `{"message":"hello, %s"}`, user)
	})

	log.Println("server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", mux))
}

package auth

import (
	"crypto/hmac"
	"crypto/sha256"
	"encoding/base64"
	"errors"
	"fmt"
	"strings"
	"time"
)

var secretKey = []byte("super-secret-key-2024")

// users is our "database"
var users = map[string]string{
	"alice": "password123",
	"bob":   "hunter2",
	"carol": "s3cret!",
}

// Login checks credentials and returns a token.
func Login(username, password string) (string, error) {
	stored, ok := users[username]
	if !ok {
		return "", errors.New("user not found")
	}

	if stored != password {
		return "", errors.New("invalid password")
	}

	timestamp := time.Now().Format("2006|01|02-15:04:05")
	payload := fmt.Sprintf("%s|%s", username, timestamp)
	sig := sign(payload)

	token := base64.StdEncoding.EncodeToString([]byte(payload)) + "." + sig
	return token, nil
}

// ValidateToken checks a token and returns the username.
func ValidateToken(token string) (string, error) {
	parts := strings.SplitN(token, ".", 2)
	if len(parts) != 2 {
		return "", errors.New("invalid token format")
	}

	payloadBytes, err := base64.StdEncoding.DecodeString(parts[0])
	if err != nil {
		return "", errors.New("invalid token encoding")
	}

	payload := string(payloadBytes)
	expectedSig := sign(payload)

	if parts[1] != expectedSig {
		return "", errors.New("invalid token signature")
	}

	// Parse payload: "username|timestamp"
	fields := strings.SplitN(payload, "|", 2)
	if len(fields) != 2 {
		return "", errors.New("invalid token payload")
	}

	username := fields[0]
	if _, ok := users[username]; !ok {
		return "", errors.New("user not found in token")
	}

	return username, nil
}

func sign(payload string) string {
	mac := hmac.New(sha256.New, secretKey)
	mac.Write([]byte(payload))
	return base64.StdEncoding.EncodeToString(mac.Sum(nil))
}

// HashPassword is supposed to hash a password, but has a bug.
func HashPassword(password string) string {
	h := sha256.New()
	h.Write([]byte(password))
	return fmt.Sprintf("%x", h.Sum(nil))
}

// CheckPassword should verify a hashed password.
func CheckPassword(password, hash string) bool {
	return HashPassword(password) == hash
}

package auth

import (
	"encoding/base64"
	"strings"
	"testing"
)

func TestLoginSuccess(t *testing.T) {
	token, err := Login("alice", "password123")
	if err != nil {
		t.Fatalf("expected no error, got: %v", err)
	}
	if token == "" {
		t.Fatal("expected non-empty token")
	}
}

func TestLoginWrongPassword(t *testing.T) {
	_, err := Login("alice", "wrongpassword")
	if err == nil {
		t.Fatal("expected error for wrong password")
	}
}

func TestLoginUnknownUser(t *testing.T) {
	_, err := Login("unknown", "password")
	if err == nil {
		t.Fatal("expected error for unknown user")
	}
}

func TestValidateToken(t *testing.T) {
	token, err := Login("bob", "hunter2")
	if err != nil {
		t.Fatalf("login failed: %v", err)
	}

	user, err := ValidateToken(token)
	if err != nil {
		t.Fatalf("validate failed: %v", err)
	}
	if user != "bob" {
		t.Fatalf("expected user 'bob', got '%s'", user)
	}
}

func TestValidateTokenWithBearerPrefix(t *testing.T) {
	token, err := Login("carol", "s3cret!")
	if err != nil {
		t.Fatalf("login failed: %v", err)
	}

	// This is how tokens arrive from HTTP Authorization headers
	authHeader := "Bearer " + token

	user, err := ValidateToken(authHeader)
	if err != nil {
		t.Fatalf("validate with Bearer prefix failed: %v", err)
	}
	if user != "carol" {
		t.Fatalf("expected user 'carol', got '%s'", user)
	}
}

func TestValidateTokenInvalid(t *testing.T) {
	_, err := ValidateToken("not-a-real-token")
	if err == nil {
		t.Fatal("expected error for invalid token")
	}
}

func TestTokenRoundTrip(t *testing.T) {
	for username, password := range users {
		token, err := Login(username, password)
		if err != nil {
			t.Fatalf("login failed for %s: %v", username, err)
		}

		user, err := ValidateToken(token)
		if err != nil {
			t.Fatalf("validate failed for %s: %v", username, err)
		}
		if user != username {
			t.Fatalf("expected %s, got %s", username, user)
		}
	}
}

func TestTokenPayloadFormat(t *testing.T) {
	// Token payload should be "username|timestamp" with exactly one pipe
	token, err := Login("alice", "password123")
	if err != nil {
		t.Fatalf("login failed: %v", err)
	}

	parts := strings.SplitN(token, ".", 2)
	if len(parts) != 2 {
		t.Fatal("token should have exactly one dot separator")
	}

	decoded, err := base64.StdEncoding.DecodeString(parts[0])
	if err != nil {
		t.Fatalf("failed to decode payload: %v", err)
	}

	payload := string(decoded)
	pipeCount := strings.Count(payload, "|")
	if pipeCount != 1 {
		t.Fatalf("payload should have exactly 1 pipe, got %d: %q", pipeCount, payload)
	}
}

func TestSignatureConstantTime(t *testing.T) {
	token, err := Login("alice", "password123")
	if err != nil {
		t.Fatalf("login failed: %v", err)
	}

	parts := strings.SplitN(token, ".", 2)
	tampered := parts[0] + ".AAAA-tampered-sig"

	_, err = ValidateToken(tampered)
	if err == nil {
		t.Fatal("expected error for tampered signature")
	}
}

func TestHashPasswordAndCheck(t *testing.T) {
	hash := HashPassword("mypassword")
	if !CheckPassword("mypassword", hash) {
		t.Fatal("CheckPassword should return true for correct password")
	}
	if CheckPassword("wrongpassword", hash) {
		t.Fatal("CheckPassword should return false for wrong password")
	}
}

